      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');

let projectsStore = [];

async function createProject(name) {
  const project = {
    id: randomUUID(),
    name,
  };
  projectsStore.push(project);
  return project;
}

async function getAllProjects() {
  return projectsStore;
}

module.exports = {
  createProject,
  getAllProjects,
};"
