    {
      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');

let tasksStore = [];

async function createTask(projectId, title) {
  const task = {
    id: randomUUID(),
    projectId,
    title,
    status: 'todo',
  };
  tasksStore.push(task);
  return task;
}

async function getAllTasks(projectId, status) {
  let tasks = tasksStore.filter(task => task.projectId === projectId);
  if (status) {
    tasks = tasks.filter(task => task.status === status);
  }
  return tasks;
}

async function updateTaskStatus(projectId, taskId, status) {
  const task = tasksStore.find(task => task.id === taskId && task.projectId === projectId);
  if (!task) {
    throw new Error('Task not found');
  }
  task.status = status;
  return task;
}

module.exports = {
  createTask,
  getAllTasks,
  updateTaskStatus,
};"
